const input = $json.body || {};
let text = "";
if (input.text) text = input.text;
else if (input.url) text = input.url;
else if (input.headline) text = input.headline;
else text = JSON.stringify(input);
text = text.toLowerCase().replace(/[^a-z0-9\\s-]/g, " ").replace(/\\s+/g, " ").trim();
return [{json: {normalized_text: text, timestamp: new Date().toISOString()}}];

const text = $json.normalized_text || "";

// 🔥 fallback if empty input
if (!text || text.length === 0) {
  return [{
    json: {
      query: "latest news technology business",
      keywords: ["news", "technology", "business"],
      is_fallback: true
    }
  }];
}

// split words
const words = text.split(" ").filter(w => w.length > 3);

// 🔥 fallback if too short
if (words.length === 0) {
  return [{
    json: {
      query: "latest news",
      keywords: ["news"],
      is_fallback: true
    }
  }];
}

// remove stopwords
const stopwords = [
  "the","and","are","that","this","have","from","with","been","were",
  "than","also","will","would","could","they","them","their","what",
  "when","which","your","about","after","before","into","over"
];

const filtered = words.filter(w => !stopwords.includes(w));

// 🔥 fallback if nothing left
if (filtered.length === 0) {
  return [{
    json: {
      query: "breaking news",
      keywords: ["news"],
      is_fallback: true
    }
  }];
}

// 🔥 frequency scoring
const freq = {};
filtered.forEach(w => {
  freq[w] = (freq[w] || 0) + 1;
});

// sort by importance
const sorted = Object.entries(freq)
  .sort((a, b) => b[1] - a[1])
  .map(e => e[0]);

const top = sorted.slice(0, 6);

// 🔥 FINAL OUTPUT (IMPORTANT)
return [{
  json: {
    query: top.join(" "),
    keywords: top,
    is_fallback: false
  }
}];

const articles = $json.articles || [];

// ✅ FIXED node reference
const query = $node["Keyword Extraction"].json.query || "";
const keywords = ($node["Keyword Extraction"].json.query || "").split(" ");

const TRUSTED = ["bbc", "reuters", "associated press", "ap", "cnn", "guardian", "nytimes", "washington post", "ft", "economist", "npr"];

let matchCount = 0, trustedSources = 0, relatedArticles = [];

if (!articles || articles.length === 0) {
  return [{
    json: {
      query_used: query,
      match_count: 0,
      trusted_sources: 0,
      credibility: "LOW",
      related_articles: []
    }
  }];
}

for (let article of articles) {
  const title = (article.title || "").toLowerCase();
  const source = (article.source?.name || "").toLowerCase();

  let score = 0, matched = [];

  for (let kw of keywords) {
    const k = kw.toLowerCase();
    if (title.includes(k)) {
      score += 3;
      matched.push(kw);
    }
  }

  if (matched.length >= 1 || score >= 2) {
    matchCount++;
    relatedArticles.push(article.url);
  }

  if (TRUSTED.some(t => source.includes(t))) {
    trustedSources++;
  }
}

let credibility = "LOW";

if (trustedSources >= 3) credibility = "HIGH";
else if (trustedSources >= 2 && matchCount >= 2) credibility = "HIGH";
else if (trustedSources >= 1 && matchCount >= 2) credibility = "MEDIUM";
else if (matchCount >= 3) credibility = "MEDIUM";

return [{
  json: {
    query_used: query,
    match_count: matchCount,
    trusted_sources: trustedSources,
    credibility: credibility,
    related_articles: relatedArticles.slice(0, 5)
  }
}];
